// Turn a posted ordered point list into a weather-aware route plan.
// Body: { points: [{lat,lon}, ...], speed?: number, startTime?: number(ms) }.
// points[0] is the origin (the boat); the rest are waypoints in visiting order.
async function getRoutePlan(c: any) {
  // Tunable budget + default speed from config
  const maxWaypoints = (config.get('ROUTE_MAX_WAYPOINTS') as number) ?? 12;
  const defaultSpeed = (config.get('ROUTE_DEFAULT_SPEED_KNOTS') as number) ?? 5;

  // Parse the JSON body defensively — malformed JSON is a 400
  let body: any;
  try {
    body = await c.req.json();
  } catch (err) {
    return c.json({ error: true, message: 'Request body must be valid JSON' }, 400);
  }

  // --- Validate the points array ---
  const rawPoints = body && body.points;
  if (!Array.isArray(rawPoints) || rawPoints.length < 2) {
    return c.json({ error: true, message: 'Provide at least 2 points: the origin and one waypoint' }, 400);
  }
  // Cap waypoints (excludes the origin) to bound per-leg weather calls
  if (rawPoints.length - 1 > maxWaypoints) {
    return c.json({ error: true, message: 'Too many waypoints — maximum is ' + maxWaypoints }, 400);
  }

  // Each point must have in-range numeric lat/lon; normalize to {lat,lon}
  const points: any[] = [];
  for (let i = 0; i < rawPoints.length; i++) {
    const p = rawPoints[i];
    const lat = p ? Number(p.lat) : NaN;
    const lon = p ? Number(p.lon) : NaN;
    if (isNaN(lat) || isNaN(lon) || lat < -90 || lat > 90 || lon < -180 || lon > 180) {
      return c.json({ error: true, message: 'Point ' + i + ' has invalid coordinates (lat -90..90, lon -180..180)' }, 400);
    }
    points.push({ lat, lon });
  }

  // --- Validate optional speed (positive knots) ---
  let speed = defaultSpeed;
  if (body.speed !== undefined && body.speed !== null) {
    const s = Number(body.speed);
    if (isNaN(s) || s <= 0) {
      return c.json({ error: true, message: 'speed must be a positive number (knots)' }, 400);
    }
    speed = s;
  }

  // --- Validate optional startTime (UTC ms); default to now ---
  let startTime = Date.now();
  if (body.startTime !== undefined && body.startTime !== null) {
    const t = Number(body.startTime);
    if (isNaN(t)) {
      return c.json({ error: true, message: 'startTime must be a timestamp in milliseconds' }, 400);
    }
    startTime = t;
  }

  // Assemble the tunable warning thresholds from config
  const thresholds = {
    headwindAngleDeg: (config.get('ROUTE_HEADWIND_ANGLE_DEG') as number) ?? 60,
    headwindMinKnots: (config.get('ROUTE_HEADWIND_MIN_KNOTS') as number) ?? 10,
    lowVisPrecipMm: (config.get('ROUTE_LOW_VIS_PRECIP_MM') as number) ?? 2,
    lowVisCloudPct: (config.get('ROUTE_LOW_VIS_CLOUD_PCT') as number) ?? 95,
    pressureLowHpa: (config.get('ROUTE_PRESSURE_LOW_HPA') as number) ?? 1005,
    pressureDropHpa: (config.get('ROUTE_PRESSURE_DROP_HPA') as number) ?? 3
  };

  // Delegate to the orchestrator; wrap unexpected runtime errors in a 500
  try {
    const result: any = await functions.call('planRoute', points, speed, startTime, thresholds, maxWaypoints);

    // Map the Result to HTTP: validation -> 400, weather outage -> 502
    if (!result.ok) {
      const status = result.error.code === 'ROUTE_WEATHER_API_ERROR' ? 502 : 400;
      return c.json({ error: true, message: result.error.message }, status);
    }

    return c.json(result.data);
  } catch (err) {
    log.error('Failed to compute route plan: ' + (err as Error).message);
    return c.json({ error: true, message: 'Failed to compute route plan' }, 500);
  }
}
